    private var lastGravity = floatArrayOf(0f, 0f, 0f)

    private var isStabilizing = false
    private var stabilityStartTime = 0L
    private var captureCount = 0
    private var targetCaptureCount = 1

private fun startStabilityTrigger() {
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    targetCaptureCount = if (prefs.getBoolean("successive_enabled", false)) prefs.getInt("successive_count", 3) else 1
    captureCount = 0
    isStabilizing = true
    stabilityStartTime = 0

    sensorManager.registerListener(this, accelerometer, android.hardware.SensorManager.SENSOR_DELAY_GAME)
    sensorManager.registerListener(this, gravitySensor, android.hardware.SensorManager.SENSOR_DELAY_GAME)

    DebugLogger.log("STABILIZER", "Started. Targets: $targetCaptureCount")
    hapticPulse(30) // Initial engagement tick
    startVibrationLoop()
}

private fun startVibrationLoop() {
    if (!isStabilizing) return

    // 1. Check Leveling
    val tilt = Math.abs(lastGravity[2]) // Z-axis gravity
    // If Z is < 8, the phone is tilted more than ~35 degrees
    if (tilt < 7.5f) {
        // Distinct 'Level Me' pattern
        val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
        v.vibrate(VibrationEffect.createOneShot(100, 40))
        handler.postDelayed({ startVibrationLoop() }, 1000)
        return
    }

    // 2. Calculate Jitter
    val magnitude = Math.sqrt((lastLinearAcc[0] * lastLinearAcc[0] + lastLinearAcc[1] * lastLinearAcc[1] + lastLinearAcc[2] * lastLinearAcc[2]).toDouble()).toFloat()

    // 3. Map to Amplitude (Stealth Capped at 100/255)
    // High movement (>1.0) = 100 amplitude. Low movement (<0.2) = 0 amplitude.
    val amplitude = ((magnitude - 0.2f) * 120).toInt().coerceIn(0, 100)

    val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
    if (amplitude > 15) {
        v.vibrate(VibrationEffect.createOneShot(100, amplitude))
        stabilityStartTime = 0
    } else {
        // Hand is steady
        if (stabilityStartTime == 0L) stabilityStartTime = System.currentTimeMillis()

        if (System.currentTimeMillis() - stabilityStartTime > 400) {
            // LOCKED: Capture Sequence
            executeStabilizedCapture()
            return
        }
    }

    handler.postDelayed({ startVibrationLoop() }, 120)
}

private fun executeStabilizedCapture() {
    // 1. Force Focus Tap
    val metrics = resources.displayMetrics
    val x = metrics.widthPixels / 2f
    val y = metrics.heightPixels / 2f
    val focusPath = Path().apply { moveTo(x, y) }
    dispatchGesture(GestureDescription.Builder().addStroke(GestureDescription.StrokeDescription(focusPath, 0, 40)).build(), null, null)

    // 2. Wait for Focus, then Shutter
    handler.postDelayed({
        smartShutterClick()
        captureCount++

        if (captureCount < targetCaptureCount) {
            DebugLogger.log("STABILIZER", "Capture $captureCount success. Resetting for next.")
            hapticPulse(150) // Confirmation pulse
            stabilityStartTime = 0
            handler.postDelayed({ startVibrationLoop() }, 1500)
        } else {
            stopStabilitySystem()
            speak("Batch complete", true)
        }
    }, 200)
}

private fun stopStabilitySystem() {
    isStabilizing = false
    sensorManager.unregisterListener(this)
    val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
    v.cancel()
}

