101 |         val isScreenOn = pm.isInteractive
102 |         if (!prefs.getBoolean("keys_enabled", true)) return false
103 | 
104 |         val keyCode = event.keyCode
105 |         val action = event.action
106 |         val isLongPress = (event.eventTime - event.downTime) > 600
107 | 
108 |         // 1. Camera Context & Emergency Logic
109 |         val root = rootInActiveWindow
110 |         val pkg = root?.packageName?.toString() ?: ""
111 |         val isCamOpen = pkg.contains("camera") || pkg.contains("lens")
112 | 
113 |         if (isCam && (keyCode == KeyEvent.KEYCODE_VOLUME_UP || keyCode == KeyEvent.KEYCODE_VOLUME_DOWN)) {
114 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP && action == KeyEvent.ACTION_UP) {
115 |                 val now = System.currentTimeMillis()
116 |                 if (now - lastUpTime < 400 && blockerOverlay != null) {
117 |                     removeTouchBlocker()
118 |                     return true 
119 |                 }
120 |                 lastUpTime = now
121 |             }
122 | 
123 |             if (action == KeyEvent.ACTION_UP) {
124 |                 startStabilityTrigger()
125 |                 return true
126 |             }
127 |         }
128 | 
129 |         // 2. Headset Hijack Logic (Highest Priority)
130 |         val isHeadsetKey = keyCode == KeyEvent.KEYCODE_HEADSETHOOK || 
131 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PLAY_PAUSE || 
132 |                           keyCode == KeyEvent.KEYCODE_MEDIA_NEXT || 
133 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PREVIOUS
134 | 
135 |         if (isHeadsetKey) {
136 |             if (action == KeyEvent.ACTION_DOWN) {
137 |                 if (event.repeatCount == 0) {
138 |                     lastHeadsetDownTime = event.eventTime
139 |                     val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
140 |                     val wl = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "UniversalApp::KeyHijack")
141 |                     wl.acquire(500)
142 |                 }
143 |                 return true 
144 |             }
145 |             if (action == KeyEvent.ACTION_UP) {
146 |                 val duration = event.eventTime - lastHeadsetDownTime
147 |                 val type = if (duration > 600) "L" else "S"
148 |                 DebugLogger.log("HEADSET_RAW", "Press: ${duration}ms -> Added: $type")
149 |                 handler.removeCallbacks(headsetGestureRunnable)
150 |                 
151 |                 gestureSequence += type
152 |                 
153 |                 handler.postDelayed(headsetGestureRunnable, 450)
154 |                 return true
155 |             }
156 |         }
157 | 
158 |         // 3. Volume Key DOWN Logic
159 |         if (action == KeyEvent.ACTION_DOWN) {
160 |             val now = System.currentTimeMillis()
161 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
162 |                 isVolUpPressed = true
163 |                 isWaitingForTapHold = (now - lastUpTime < 800)
164 |             }
165 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
166 |                 isVolDownPressed = true
167 |                 isWaitingForDownTapHold = (now - lastDownTime < 800)
168 |             }
169 | 
170 |             if (event.repeatCount > 0) return true
171 |             if (isVolUpPressed && isVolDownPressed) return true
172 | 
173 |             when (keyCode) {
174 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
175 |                     if (event.repeatCount == 0) {
176 |                         isLongPressTriggered = false
177 |                         handler.postDelayed(volUpLongPressRunnable, 5000)
178 |                     }
179 |                     val now = System.currentTimeMillis()
180 |                     if (now - lastUpTime < CLICK_GAP) upCount++ else upCount = 1
181 |                     lastUpTime = now
182 |                     return true
183 |                 }
184 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
185 |                     if (event.repeatCount == 0) {
186 |                         isLongPressTriggered = false
187 |                         handler.postDelayed(volDownBatchRunnable, 5000)
188 |                     }
189 |                     val now = System.currentTimeMillis()
190 |                     if (now - lastDownTime < CLICK_GAP) downCount++ else downCount = 1
191 |                     lastDownTime = now
192 |                     return true
193 |                 }
194 |             }
195 |         }
196 | 
197 |         // 4. Volume Key UP Logic
198 |         if (action == KeyEvent.ACTION_UP) {
199 |             val wasBothPressed = isVolUpPressed && isVolDownPressed
200 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) isVolUpPressed = false
201 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) isVolDownPressed = false
202 | 
203 |             if (wasBothPressed) {
204 |                 val intent = Intent(this, PlaybackService::class.java)
205 |                 intent.action = if (isLongPress) "RESET" else "PAUSE"
206 |                 startService(intent)
207 |                 return true
208 |             }
209 | 
210 | 
211 | 
212 |             when (keyCode) {
213 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
214 |                     handler.removeCallbacks(volUpLongPressRunnable)
215 |                     if (isLongPressTriggered) {
216 |                         isLongPressTriggered = false
217 |                         upCount = 0
218 |                         isWaitingForTapHold = false
219 |                         return true
220 |                     }
221 |                     
222 |                     val duration = event.eventTime - event.downTime
223 |                     if (isWaitingForTapHold && duration > 500) {
224 |                         toggleCamera()
225 |                         isWaitingForTapHold = false
226 |                         upCount = 0 
227 |                         return true 
228 |                     }
229 |                     isWaitingForTapHold = false
230 |                     handlePress("UP", upCount, isLongPress)
231 |                 }
232 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
233 |                     handler.removeCallbacks(volDownBatchRunnable)
234 |                     if (isLongPressTriggered) return true
235 |                     
236 |                     val duration = event.eventTime - event.downTime
237 |                     if (isWaitingForDownTapHold && duration > 500) {
238 |                         triggerReset()
239 |                         isWaitingForDownTapHold = false
240 |                         downCount = 0
241 |                         return true
242 |                     }
243 |                     isWaitingForDownTapHold = false
244 |                     handlePress("DOWN", downCount, isLongPress)
245 |                 }
246 |             }
247 |             return true
248 |         }
249 | 
250 |         return super.onKeyEvent(event)
251 |     }
