350 |     private fun prepareWideLens(): Boolean {
351 |         val root = rootInActiveWindow ?: return false
352 |         
353 |         var lensNode: AccessibilityNodeInfo? = null
354 |         val searchTerms = listOf(".5", "0.5", "0,5", "0.6", "0.5x", "0,5x", "ultra", "wide", "zoom out")
355 |         val bounds = Rect()
356 | 
357 |         val queue = LinkedList<AccessibilityNodeInfo>()
358 |         queue.add(root)
359 |         while (!queue.isEmpty()) {
360 |             val node = queue.poll() ?: continue
361 |             val text = node.text?.toString()?.lowercase() ?: ""
362 |             val desc = node.contentDescription?.toString()?.lowercase() ?: ""
363 |             
364 |             val match = searchTerms.find { (text.contains(it) || desc.contains(it)) && !text.contains("1x") }
365 | 
366 |             if (match != null) {
367 |                 var current: AccessibilityNodeInfo? = node
368 |                 var depth = 0
369 |                 while (current != null && depth < 6) {
370 |                     if (current.isClickable) {
371 |                         lensNode = current
372 |                         break
373 |                     }
374 |                     current = current.parent
375 |                     depth++
376 |                 }
377 |                 if (lensNode != null) break
378 |             }
379 |             for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
380 |         }
381 | 
382 |         return if (lensNode != null) {
383 |             // Try Virtual Click first (Robust Verification)
384 |             val success = lensNode.performAction(AccessibilityNodeInfo.ACTION_CLICK)
385 |             
386 |             if (success) {
387 |                 DebugLogger.log("LENS_FLOW", "Virtual click SUCCESS")
388 |                 speak("Wide lens activated", true)
389 |                 hapticPulse(50)
390 |                 true
391 |             } else {
392 |                 // Fallback to Physical Tap for Samsung/Google Camera
393 |                 lensNode.getBoundsInScreen(bounds)
394 |                 val x = bounds.centerX().toFloat()
395 |                 val y = bounds.centerY().toFloat()
396 |                 
397 |                 val clickPath = Path().apply { moveTo(x, y) }
398 |                 val gesture = GestureDescription.Builder()
399 |                     .addStroke(GestureDescription.StrokeDescription(clickPath, 0, 50))
400 |                     .build()
401 |                 
402 |                 dispatchGesture(gesture, null, null)
403 |                 DebugLogger.log("LENS_FLOW", "Virtual click REJECTED. Physical tap dispatched to $x, $y")
404 |                 // Return false so the retry loop continues to verify the switch
405 |                 false
406 |             }
407 |         } else {
408 |             false
409 |         }
410 |     }
