412 |     private fun attemptLensSwitch(retries: Int) {
413 |         if (!isLensSwitchPending) return
414 |         
415 |         if (retries <= 0) {
416 |             DebugLogger.log("LENS_FLOW", "Search timed out. Applying fallback coordinates.")
417 |             clickLensCoordinatesFallback()
418 |             isLensSwitchPending = false
419 |             val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
420 |             if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
421 |             return
422 |         }
423 | 
424 |         handler.postDelayed({
425 |             if (!isLensSwitchPending) return@postDelayed
426 |             
427 |             val success = prepareWideLens()
428 |             if (success) {
429 |                 DebugLogger.log("LENS_FLOW", "Lens switch CONFIRMED.")
430 |                 isLensSwitchPending = false
431 |                 val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
432 |                 if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
433 |             } else {
434 |                 attemptLensSwitch(retries - 1)
435 |             }
436 |         }, 500)
437 |     }
