470 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
471 |         targetCaptureCount = if (prefs.getBoolean("successive_enabled", false)) prefs.getInt("successive_count", 3) else 1
472 |         captureCount = 0
473 |         isStabilizing = true
474 |         stabilityStartTime = 0
475 |         
476 |         sensorManager.registerListener(this, accelerometer, android.hardware.SensorManager.SENSOR_DELAY_GAME)
477 |         sensorManager.registerListener(this, gravitySensor, android.hardware.SensorManager.SENSOR_DELAY_GAME)
