484 |     private fun startVibrationLoop() {
485 |         if (!isStabilizing) return
486 |         
487 |         // 1. Check Leveling
488 |         val tilt = Math.abs(lastGravity[2]) // Z-axis gravity
489 |         // If Z is < 8, the phone is tilted more than ~35 degrees
490 |         if (tilt < 7.5f) {
491 |             // Distinct 'Level Me' pattern
492 |             val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
493 |             v.vibrate(VibrationEffect.createOneShot(100, 40))
494 |             handler.postDelayed({ startVibrationLoop() }, 1000)
495 |             return
496 |         }
497 | 
498 |         // 2. Calculate Jitter
499 |         val magnitude = Math.sqrt((lastLinearAcc[0] * lastLinearAcc[0] + lastLinearAcc[1] * lastLinearAcc[1] + lastLinearAcc[2] * lastLinearAcc[2]).toDouble()).toFloat()
500 |         
501 |         // 3. Map to Amplitude (Stealth Capped at 100/255)
502 |         // High movement (>1.0) = 100 amplitude. Low movement (<0.2) = 0 amplitude.
503 |         val amplitude = ((magnitude - 0.2f) * 120).toInt().coerceIn(0, 100)
504 |         
505 |         val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
506 |         if (amplitude > 15) {
507 |             v.vibrate(VibrationEffect.createOneShot(100, amplitude))
508 |             stabilityStartTime = 0
509 |         } else {
510 |             // Hand is steady
511 |             if (stabilityStartTime == 0L) stabilityStartTime = System.currentTimeMillis()
512 |             
513 |             if (System.currentTimeMillis() - stabilityStartTime > 400) {
514 |                 // LOCKED: Capture Sequence
515 |                 executeStabilizedCapture()
516 |                 return
517 |             }
518 |         }
519 | 
520 |         handler.postDelayed({ startVibrationLoop() }, 120)
521 |     }
522 | 
523 |     private fun executeStabilizedCapture() {
524 |         // 1. Force Focus Tap
525 |         val metrics = resources.displayMetrics
526 |         val x = metrics.widthPixels / 2f
527 |         val y = metrics.heightPixels / 2f
528 |         val focusPath = Path().apply { moveTo(x, y) }
529 |         dispatchGesture(GestureDescription.Builder().addStroke(GestureDescription.StrokeDescription(focusPath, 0, 40)).build(), null, null)
530 |         
531 |         // 2. Wait for Focus, then Shutter
532 |         handler.postDelayed({
533 |             smartShutterClick()
534 |             captureCount++
535 |             
536 |             if (captureCount < targetCaptureCount) {
537 |                 DebugLogger.log("STABILIZER", "Capture $captureCount success. Resetting for next.")
538 |                 hapticPulse(150) // Confirmation pulse
539 |                 stabilityStartTime = 0
540 |                 handler.postDelayed({ startVibrationLoop() }, 1500)
541 |             } else {
542 |                 stopStabilitySystem()
543 |                 speak("Batch complete", true)
544 |             }
545 |         }, 200)
546 |     }
