565 |     private fun smartShutterClick() {
566 |         val root = rootInActiveWindow
567 |         val pkg = root?.packageName?.toString() ?: ""
568 |         val isCamera = pkg.contains("camera") || pkg.contains("lens")
569 | 
570 |         if (!isCamera) {
571 |             DebugLogger.log("SHUTTER", "Blocked: Camera not in foreground ($pkg)")
572 |             speak("Camera is not launched yet", true)
573 |             return
574 |         }
575 | 
576 |         // --- Successive Capture Logic ---
577 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
578 |         val isSuccessive = prefs.getBoolean("successive_enabled", false)
579 |         if (isSuccessive && successiveRemaining == 0) {
580 |             successiveRemaining = prefs.getInt("successive_count", 3) - 1
581 |             triggerSuccessiveLoop()
582 |         }
583 | 
584 |         var foundNode: AccessibilityNodeInfo? = null
585 |         if (root != null) {
586 |             val targets = listOf("shutter", "take picture", "capture", "camera_shutter", "bottom_bar_shutter")
587 |             val queue = LinkedList<AccessibilityNodeInfo>()
588 |             queue.add(root)
589 |             
590 |             while (!queue.isEmpty()) {
591 |                 val node = queue.poll() ?: continue
592 |                 val id = node.viewIdResourceName?.lowercase() ?: ""
593 |                 val desc = node.contentDescription?.toString()?.lowercase() ?: ""
594 |                 
595 |                 if (targets.any { id.contains(it) || desc.contains(it) } && node.isClickable) {
596 |                     foundNode = node
597 |                     break
598 |                 }
599 |                 for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
600 |             }
601 |         }
602 | 
603 |         if (foundNode != null) {
604 |             DebugLogger.log("AUTO", "Smart Shutter Active")
605 |             if (successiveRemaining <= 0) speak("Capturing image")
606 |             hapticPulse(100)
607 |             foundNode.performAction(android.view.accessibility.AccessibilityNodeInfo.ACTION_CLICK)
608 |         } else {
609 |             DebugLogger.log("AUTO", "Shutter Node Missing")
610 |             if (successiveRemaining <= 0) speak("Shutter not visible, using fallback")
611 |             clickShutterCoordinates()
612 |         }
613 |     }
614 | 
615 |     private fun triggerSuccessiveLoop() {
616 |         if (successiveRemaining > 0) {
617 |             handler.postDelayed({ 
618 |                 DebugLogger.log("AUTO", "Successive Capture: $successiveRemaining left")
619 |                 smartShutterClick()
620 |                 successiveRemaining--
621 |                 triggerSuccessiveLoop()
622 |             }, 1200)
623 |         } else {
624 |             val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
625 |             val total = prefs.getInt("successive_count", 3)
626 |             // The first image was the anchor, so total-1 images are data
627 |             speak("Batch capture complete. ${total - 1} images queued.", true)
628 |             hapticPulse(200)
629 |         }
630 |     }
