634 |             val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
635 |             if (v.hasVibrator()) {
636 |                 // Use low amplitude (50/255) for stealth
637 |                 val stealthMs = if (ms > 100) 60L else ms 
638 |                 v.vibrate(VibrationEffect.createOneShot(stealthMs, 50))
639 |             }
640 |         } catch (e: Exception) { 
641 |             DebugLogger.log("HAPTIC_ERR", "${e.message}")
642 |         }
643 |     }
