    private val handler = Handler(Looper.getMainLooper())
    private lateinit var sensorManager: android.hardware.SensorManager
    private var accelerometer: android.hardware.Sensor? = null
    private var gravitySensor: android.hardware.Sensor? = null

    private var lastLinearAcc = floatArrayOf(0f, 0f, 0f)
    private var lastGravity = floatArrayOf(0f, 0f, 0f)
    private var lastLogTime = 0L

    private var isStabilizing = false
    private var stabilityStartTime = 0L
    private var captureCount = 0
    private var targetCaptureCount = 1

private fun startStabilityTrigger() {
    if (isStabilizing) return
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    targetCaptureCount = if (prefs.getBoolean("successive_enabled", false)) prefs.getInt("successive_count", 3) else 1
    captureCount = 0
    isStabilizing = true
    stabilityStartTime = 0

    sensorManager.registerListener(this, accelerometer, android.hardware.SensorManager.SENSOR_DELAY_GAME)
    sensorManager.registerListener(this, gravitySensor, android.hardware.SensorManager.SENSOR_DELAY_GAME)

    DebugLogger.log("STAB_INIT", "Target Count: $targetCaptureCount")
    hapticPulse(30)
    startVibrationLoop()
}

private fun startVibrationLoop() {
    if (!isStabilizing) return

    // 1. Check Leveling (Z-axis gravity > 8.0 means screen is roughly flat)
    val tilt = Math.abs(lastGravity[2])
    if (tilt < 7.8f) {
        if (System.currentTimeMillis() - lastLogTime > 2000) {
            DebugLogger.log("STAB_WARN", "Tilt detected: $tilt. Level your arm.")
            lastLogTime = System.currentTimeMillis()
        }
        val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
        v.vibrate(VibrationEffect.createOneShot(80, 40))
        handler.postDelayed({ startVibrationLoop() }, 1000)
        return
    }

    // 2. Calculate Jitter Magnitude
    val magnitude = Math.sqrt((lastLinearAcc[0] * lastLinearAcc[0] + lastLinearAcc[1] * lastLinearAcc[1] + lastLinearAcc[2] * lastLinearAcc[2]).toDouble()).toFloat()

    // 3. Map to Amplitude (Threshold: 0.2 m/s2)
    val amplitude = ((magnitude - 0.15f) * 150).toInt().coerceIn(0, 100)

    if (System.currentTimeMillis() - lastLogTime > 500) {
        DebugLogger.log("STAB_SENSE", "Mag: ${String.format("%.2f", magnitude)} | Amp: $amplitude")
        lastLogTime = System.currentTimeMillis()
    }

    val v = getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
    if (amplitude > 10) {
        v.vibrate(VibrationEffect.createOneShot(120, amplitude))
        stabilityStartTime = 0
    } else {
        // Hand is perfectly steady
        if (stabilityStartTime == 0L) stabilityStartTime = System.currentTimeMillis()

        if (System.currentTimeMillis() - stabilityStartTime > 400) {
            executeStabilizedCapture()
            return
        }
    }

    handler.postDelayed({ startVibrationLoop() }, 120)
}

